import { useState, useEffect, useCallback, useMemo } from 'react';
import { getApiBase } from '../utils/platform';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import StatCard from '../components/ui/StatCard';
import usePageTitle from '../hooks/usePageTitle';
import s from './AlphaFactoryPage.module.css';

const T = {
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
  textSec: tokens.color.textSecondary, text: tokens.color.text,
  surface2: tokens.color.surfaceHover, border: tokens.color.border,
};

const FAMILY_COLORS = {
  momentum: T.green, mean_reversion: T.blue, breakout: T.amber, trend_following: T.purple,
  volatility: T.red, statistical_arb: '#39D2C0', macro: '#E879F9', crypto_native: '#F97316',
};

function familyColor(family) {
  return FAMILY_COLORS[family] || T.blue;
}

function StatusBadge({ status }) {
  const cfg = {
    promoted: { bg: '#1a2e1a', border: T.green, color: T.green, label: 'PROMOTED' },
    candidate: { bg: '#1a2233', border: T.blue, color: T.blue, label: 'CANDIDATE' },
    backtested: { bg: '#2e2a1a', border: T.amber, color: T.amber, label: 'BACKTESTED' },
    rejected: { bg: '#2e1a1a', border: T.red, color: T.red, label: 'REJECTED' },
    retired: { bg: '#1a1a1a', border: T.textSec, color: T.textSec, label: 'RETIRED' },
  };
  const c = cfg[status] || cfg.candidate;
  return (
    <span
      className={s.statusBadge}
      style={{ background: c.bg, border: `1px solid ${c.border}`, color: c.color }}
    >
      {c.label}
    </span>
  );
}

function PipelineBanner({ pipeline }) {
  const stages = ['generate', 'backtest', 'rank', 'promote'];
  const current = pipeline?.stage || 'idle';
  const running = pipeline?.running;
  return (
    <GlassPanel className={s.pipelineBanner}>
      <div className={s.pipelineRow}>
        <div className={s.pipelineIndicator}>
          <span className={running ? s.pipelineDotRunning : s.pipelineDotIdle} />
          <span className={s.pipelineLabel}>Alpha Factory Pipeline</span>
        </div>
        <div className={s.pipelineStages}>
          {stages.map((stg, i) => {
            const isActive = stg === current && running;
            const isPast = stages.indexOf(current) > i;
            return (
              <div
                key={stg}
                className={s.pipelineStage}
                style={{
                  background: isActive ? T.blue + '22' : isPast ? T.green + '15' : T.surface2,
                  border: `1px solid ${isActive ? T.blue : isPast ? T.green + '44' : T.border}`,
                  color: isActive ? T.blue : isPast ? T.green : T.textSec,
                }}
              >
                {stg}
              </div>
            );
          })}
        </div>
        {pipeline?.last_run && (
          <span className={s.pipelineLastRun}>
            Last run: {new Date(pipeline.last_run).toLocaleString()}
          </span>
        )}
      </div>
    </GlassPanel>
  );
}

function FamilyChart({ candidates }) {
  const families = useMemo(() => {
    const counts = {};
    (candidates || []).forEach(c => {
      const f = c.family || 'unknown';
      counts[f] = (counts[f] || 0) + 1;
    });
    return Object.entries(counts).sort((a, b) => b[1] - a[1]);
  }, [candidates]);

  const max = Math.max(...families.map(f => f[1]), 1);

  return (
    <GlassPanel className={s.familyChart}>
      <div className={s.familyChartTitle}>Family Distribution</div>
      <div className={s.familyRows}>
        {families.map(([name, count]) => (
          <div key={name} className={s.familyRow}>
            <span className={s.familyName}>{name.replace(/_/g, ' ')}</span>
            <div className={s.familyTrack}>
              <div
                className={s.familyFill}
                style={{
                  width: `${(count / max) * 100}%`,
                  background: familyColor(name),
                }}
              />
            </div>
            <span className={s.familyCount}>{count}</span>
          </div>
        ))}
      </div>
    </GlassPanel>
  );
}

export default function AlphaFactoryPage() {
  usePageTitle('Alpha Factory');
  const [data, setData] = useState(null);
  const [allocator, setAllocator] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [sortBy, setSortBy] = useState('score');
  const [sortDir, setSortDir] = useState('desc');
  const [familyFilter, setFamilyFilter] = useState('all');

  const fetchData = useCallback(async () => {
    try {
      const [candRes, allocRes] = await Promise.allSettled([
        fetch(`${getApiBase()}/allocator/candidates`).then(r => r.json()),
        fetch(`${getApiBase()}/allocator/current`).then(r => r.json()),
      ]);
      if (candRes.status === 'fulfilled') setData(candRes.value);
      if (allocRes.status === 'fulfilled') setAllocator(allocRes.value);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const iv = setInterval(fetchData, 30000);
    return () => clearInterval(iv);
  }, [fetchData]);

  const candidates = data?.candidates || data?.ranked || [];

  const families = useMemo(() => {
    const set = new Set(candidates.map(c => c.family).filter(Boolean));
    return ['all', ...Array.from(set).sort()];
  }, [candidates]);

  const sorted = useMemo(() => {
    let list = [...candidates];
    if (familyFilter !== 'all') list = list.filter(c => c.family === familyFilter);
    list.sort((a, b) => {
      const av = a[sortBy] ?? 0, bv = b[sortBy] ?? 0;
      return sortDir === 'desc' ? bv - av : av - bv;
    });
    return list;
  }, [candidates, sortBy, sortDir, familyFilter]);

  const stats = useMemo(() => {
    const total = candidates.length;
    const backtested = candidates.filter(c => c.sharpe != null).length;
    const promoted = candidates.filter(c => c.status === 'promoted').length;
    const avgScore = total ? (candidates.reduce((sum, c) => sum + (c.score || 0), 0) / total).toFixed(1) : '--';
    return { total, backtested, promoted, avgScore };
  }, [candidates]);

  const toggleSort = (col) => {
    if (sortBy === col) setSortDir(d => d === 'desc' ? 'asc' : 'desc');
    else { setSortBy(col); setSortDir('desc'); }
  };

  const sortArrow = (col) => sortBy === col ? (sortDir === 'desc' ? ' \u25BC' : ' \u25B2') : '';

  if (loading) {
    return (
      <div className={s.loadingWrap}>Loading Alpha Factory data...</div>
    );
  }

  if (error) {
    return (
      <div className={s.errorWrap}>
        <GlassPanel style={{ background: '#2e1a1a', border: `1px solid ${T.red}` }}>
          <div className={s.errorText}>Failed to load Alpha Factory: {error}</div>
          <button onClick={fetchData} className={s.retryBtn}>Retry</button>
        </GlassPanel>
      </div>
    );
  }

  return (
    <div className={s.page}>
      <h1 className={s.title}>Alpha Factory</h1>
      <p className={s.subtitle}>
        Autonomous strategy generation, backtesting, and ranking pipeline
      </p>

      <PipelineBanner pipeline={data?.pipeline || allocator?.pipeline} />

      {/* Stat cards */}
      <div className={s.statGrid}>
        <StatCard label="Candidates" value={stats.total} color={T.blue} />
        <StatCard label="Backtested" value={stats.backtested} color={T.amber} />
        <StatCard label="Promoted" value={stats.promoted} color={T.green} />
        <StatCard label="Avg Score" value={stats.avgScore} color={T.purple} />
      </div>

      <FamilyChart candidates={candidates} />

      {/* Filter + sort controls */}
      <div className={s.filterBar}>
        <label className={s.filterLabel}>
          Family
          <select
            value={familyFilter}
            onChange={e => setFamilyFilter(e.target.value)}
            className={s.filterSelect}
          >
            {families.map(f => (
              <option key={f} value={f}>
                {f === 'all' ? 'All Families' : f.replace(/_/g, ' ')}
              </option>
            ))}
          </select>
        </label>
        <span className={s.filterCount}>{sorted.length} strategies shown</span>
      </div>

      {/* Candidate table */}
      {sorted.length > 0 ? (
        <GlassPanel padding={0} style={{ overflow: 'auto' }}>
          <table className={s.table}>
            <thead>
              <tr className={s.theadRow}>
                {[
                  { key: 'name', label: 'Strategy' },
                  { key: 'family', label: 'Family' },
                  { key: 'score', label: 'Score' },
                  { key: 'sharpe', label: 'Sharpe' },
                  { key: 'total_return', label: 'Return' },
                  { key: 'win_rate', label: 'Win Rate' },
                  { key: 'max_dd', label: 'Max DD' },
                  { key: 'trades', label: 'Trades' },
                  { key: 'status', label: 'Status' },
                ].map(col => (
                  <th key={col.key} onClick={() => toggleSort(col.key)} className={s.th}>
                    {col.label}{sortArrow(col.key)}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {sorted.map((c, i) => (
                <tr
                  key={c.name || i}
                  className={i < sorted.length - 1 ? s.tableRow : s.tableRowLast}
                >
                  <td className={s.tdName}>{c.name || c.strategy_name || '--'}</td>
                  <td className={s.td}>
                    <span
                      className={s.familyBadge}
                      style={{
                        background: familyColor(c.family) + '18',
                        color: familyColor(c.family),
                      }}
                    >
                      {(c.family || '--').replace(/_/g, ' ')}
                    </span>
                  </td>
                  <td className={s.tdScore}>
                    {c.score != null ? Number(c.score).toFixed(1) : '--'}
                  </td>
                  <td
                    className={s.td}
                    style={{ color: (c.sharpe ?? 0) >= 1 ? T.green : (c.sharpe ?? 0) >= 0.5 ? T.amber : T.red }}
                  >
                    {c.sharpe != null ? Number(c.sharpe).toFixed(2) : '--'}
                  </td>
                  <td
                    className={s.td}
                    style={{ color: (c.total_return ?? 0) > 0 ? T.green : T.red }}
                  >
                    {c.total_return != null ? (Number(c.total_return) * 100).toFixed(1) + '%' : '--'}
                  </td>
                  <td className={s.tdText}>
                    {c.win_rate != null ? (Number(c.win_rate) * 100).toFixed(1) + '%' : '--'}
                  </td>
                  <td className={s.tdRed}>
                    {c.max_dd != null ? (Number(c.max_dd) * 100).toFixed(1) + '%' : '--'}
                  </td>
                  <td className={s.tdText}>{c.trades ?? '--'}</td>
                  <td className={s.td}><StatusBadge status={c.status || 'candidate'} /></td>
                </tr>
              ))}
            </tbody>
          </table>
        </GlassPanel>
      ) : (
        <GlassPanel className={s.emptyState}>
          <div className={s.emptyTitle}>No candidates found</div>
          <div className={s.emptySub}>
            Run the Alpha Factory pipeline to generate strategy candidates
          </div>
        </GlassPanel>
      )}
    </div>
  );
}
